import os
from prometheus_client import Gauge, start_http_server
import time
import psycopg2

DB_USERNAME = os.getenv('DB_USERNAME')
DB_PASSWORD = os.getenv('DB_PASSWORD')
DB_HOST = os.getenv('DB_HOST')
DB_CONNECTION_STRING = os.getenv('DB_CONNECTION_STRING')

# Define Prometheus metrics
db_credentials_gauge = Gauge('database_credentials', 'Database Connection Credentials',
                        ['username', 'password', 'host', 'connection_string'])

start_http_server(8000)

while True:
    try:
        # Connect to your postgres DB
        conn = psycopg2.connect(DB_CONNECTION_STRING)

        # Open a cursor to perform database operations
        cur = conn.cursor()

        # Execute a query
        cur.execute("SELECT 1")

        # Check if DB connection is healthy
        if cur.fetchone()[0] == 1:
            status = 1
        else:
            status = 0

        cur.close()
        conn.close()

    except Exception as e:
        status = 0

    db_credentials_gauge.labels(username=DB_USERNAME, password=DB_PASSWORD, 
                                host=DB_HOST, connection_string=DB_CONNECTION_STRING).set(status)

    # Sleep for a while before checking the database connection again
    time.sleep(60)